var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"과자 부스러기, ……찢어진 휴지 조각, ……살 점 붙은 뼈다귀.","JPN":"お菓子の食べかす……破れたティッシュの切れ端……肉がついている骨。","ENG":"Cookie crumbs. Torn napkins. Meaty bones.","TWN":"餅乾渣……撕碎的廢紙……帶肉的骨頭。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"후우.","JPN":"ふぅ。","ENG":"*Sigh...*","TWN":"呼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"분명히 외출 전에 먼지 한 톨 없이, 깔끔하게 청소하고 나갔을 텐데…….","JPN":"出かける前に綺麗に片づけて、埃一つない状態にしておいたはずなのに……","ENG":"I believe I left the place sparkly clean.","TWN":"我明明出門前才打掃得一塵不染的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 또 집무실을 잔뜩 어지럽혀 놨군.","JPN":"リブ卿、また執務室を散らかしたな。","ENG":"It must be Dame Liv. She messed it up again.","TWN":"看來莉芙卿又把辦公室弄亂了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이제 한솔 경과 에리어스 경도 있는데 대체 언제 철이 들 작정인 건지.","JPN":"今はヤガミ卿とアリウス卿もいるというのに、いつになったら大人になるんだ……","ENG":"What if Sir Hansol and Dame Arius take after her? Will she ever grow up?","TWN":"現在還有楊瀚卿和埃里奧斯卿在，她到底要什麼時候才會長大呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"응? 뭐가 깨져 있는 거지?","JPN":"ん？　何か割れている……？","ENG":"Hm? Something broke.","TWN":"嗯？好像有什麼東西摔破了？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……이, 이건!?","JPN":"……こ、これは！？","ENG":"...Th-this...!","TWN":"……這…這不是？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 전원 긴급 소집이라니. 무슨 일이야, 부단장?","JPN":"全員緊急招集って、いったいどういうこと？　副団長。","ENG":"What? What's this emergency call-up about? What's going on, Deputy?","TWN":"什麼嘛，幹嘛突然全員緊急集合，有什麼事嗎，副團長？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 언니… 표정이 무서워요.","JPN":"フィオネさん……顔が怖いです。","ENG":"Fione... You look scary.","TWN":"菲奧尼姊姊……表情好恐怖。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"유감스럽게도 아주 중대한 사건이 발생했습니다.","JPN":"残念ながら、一大事が起きました。","ENG":"Something very unfortunate and tragic has happened.","TWN":"我很遺憾，這裡發生了重大事件。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……이걸 보십시오.","JPN":"……これを見てください。","ENG":"...Look.","TWN":"……請看這個。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응? 머그컵?","JPN":"ん？　マグカップ？","ENG":"Hm? It's a mug.","TWN":"嗯？馬克杯？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"깨져있네? 누가 깨뜨렸담?","JPN":"割れてるね。誰がやったんだろ。","ENG":"It's broken. Who broke it?","TWN":"破咧？是誰摔破的？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"근데 그냥 치우면 되잖아. 왜 중대한 사건이라는 거야?","JPN":"って、割れたなら片付ければいいじゃん。それの何が一大事なの？","ENG":"So? You could just get rid of it. What's so unfortunate and tragic about it?","TWN":"不過掃一下就好啦？哪是什麼重大事件？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잘 떠올려 보십시오. 이건 그냥 머그컵이 아닙니다.","JPN":"よく考えてください。これはただのマグカップではありません。","ENG":"Think hard. This isn't just a mug.","TWN":"你看仔細，這可不是普通的馬克杯。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어? 그럼 아티팩트였어? 내 눈에는 평범한 머그컵으로 보이는데?","JPN":"えっ？　もしかしてアーティファクト？　私には普通のカップに見えるんだけど。","ENG":"Then, what? Is that an Artifact? But to me, it just looks like an ordinary mug.","TWN":"喔？是人造神器嗎？我看起來就是個普通的馬克杯啊？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어라, 저 어디선가 이 컵 본 것 같아요.","JPN":"あれっ？　私、あのマグカップどこかで見た気がします。","ENG":"Err, I think I've seen this mug somewhere.","TWN":"喔喔！我好像在哪看過這個馬克杯。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아아! 이 머그컵, 단장님이 아끼는 컵이에요.","JPN":"ああっ！　このマグカップ、団長のお気に入りでした！","ENG":"Ah! It's the Captain's favorite mug.","TWN":"我想起來了！這個馬克杯，是團長很寶貝的杯子。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇습니다, 에리어스 경. 단장님이 가장 애용하는 머그컵이었죠.","JPN":"そうです、アリウス卿。団長がいちばん大事にしているマグカップなんです。","ENG":"That's right, Dame Arius. It was the Captain's favorite mug.","TWN":"沒錯，埃里奧斯卿。這是團長最喜歡的馬克杯。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그리고 지금, 이렇게 산산조각 났습니다.","JPN":"そしてそれが今、こうやって粉々になってしまいました。","ENG":"Now, it's shattered into pieces like this.","TWN":"可是現在，它已經碎碎平安了。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에이, 뭐야. 겨우 그런 걸로 전원 긴급 소집이라는 거야? 시시하게시리.","JPN":"なーんだ、そんなことで全員集めたの？　つまんない。","ENG":"Sheesh, so what? That's not serious enough to call us up. It's petty.","TWN":"哎唷～什麼嘛～不過就是個杯子，有必要全員緊急集合嗎？真無聊～"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……시시하다고요?","JPN":"……今なんと？","ENG":"...It's petty, you say?","TWN":"……你說無聊？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"말 조심하십시오, 리브 경. 이건 매우 중대한 문제입니다!","JPN":"言葉には気をつけてください、リブ卿。これはとても重大な事件なんですよ！","ENG":"Watch your mouth, Dame Liv. This is grave!","TWN":"請注意你的措辭，莉芙卿。這是非常嚴重的問題！"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐, 뭐야. 부단장, 무섭게 왜 그래…?","JPN":"な、何、副団長。怖いじゃない……","ENG":"Wh-what...? Deputy, you're scaring me...","TWN":"什…什麼嘛，副團長，你幹嘛那麼嚇人……？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예로부터 조디악 나이츠는 상명하복의 집단. 기사단 내에서 단장의 권위는 절대적입니다.","JPN":"昔ながらゾディアックナイツは上命下服の集団。騎士団で団長の権威は絶対的なものなのです。","ENG":"The Zodiac Knights have a strict hierarchy. And the Captain has absolute authority.","TWN":"自古以來，十二宮騎士團就是上命下從的組織。在騎士團內，團長的權威是不容質疑的。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 이 꼴을 보십시오.","JPN":"しかし、このざまを見てください。","ENG":"Now, look at this.","TWN":"可是你們看看，"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"최근 아무리 기사단의 기강이 다소 해이해졌거니와……","JPN":"最近いくら騎士団の雰囲気がゆるんでいるとはいえ……","ENG":"As if it's not enough that the Knights have been lacking discipline nowadays…","TWN":"最近不僅騎士團的紀律渙散……"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"집무실에 들어와 단장의 머그컵을 깨고, 심지어 그 사실을 은닉하고자 하는 사람이 있다고요?","JPN":"執務室に入り、団長のマグカップを割り、ましてやそれを隠ぺいしようとしている人がいるなんて！","ENG":"Someone sneaked into her office, broke her favorite mug, and tried to hide the truth?","TWN":"現在還進到辦公室摔破團長的馬克杯？甚至還有人企圖隱瞞事實？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이건 명백히 단장의 권위를 짓밟은 행태이자, 해석에 따라 <color=#ffd34c>하극상</color>으로도 간주할 수 있습니다.","JPN":"これは団長の権威を踏みにじる行為であり、場合によっては<color=#ffd34c>下剋上</color>とみなすこともできる行為です。","ENG":"This isn't just an insult to the Captain, but it's <color=#ffd34c>insubordination</color>.","TWN":"這分明就是在踐踏團長的權威，也可以解讀為<color=#ffd34c>以下犯上</color>。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에엥? 고작 머그컵 하나 깨진 걸로 하극상까지 간다고? 비약이 너무 심한 거 같은데?","JPN":"ええ？　マグカップ1つ割ったぐらいで下剋上とか、考えすぎじゃない？","ENG":"What? How does a broken mug lead to insubordination? I think that's a huge leap of logic.","TWN":"什麼？不過是摔破一個馬克杯，有必要解讀成以下犯上嗎？會不會想像力太豐富？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요.","JPN":"いえ。","ENG":"I don't think so.","TWN":"不。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저는 이 사건, 로웰 가 고조부의 명예를 걸고 반드시 범인을 색출해낼 겁니다.","JPN":"私はこの事件……ローウェル家の高祖父の名にかけて必ず犯人を見つけ出してやります。","ENG":"I swear on my great grandfather's honor that I'll find out who did this.","TWN":"我以勞威爾家族曾曾祖父的名譽發誓，我一定會找出這個事件的犯人！"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 후, 그자의 해이해진 기강을 철저하게 바로잡아드리죠.","JPN":"そして、そのたるみ切った態度もしっかりと正すつもりです。","ENG":"And I'll straighten up their slackening discipline.","TWN":"然後徹底糾正那個人渙散的紀律。"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……부단장의 명예를 거는 게 아니라?","JPN":"……副団長の名にかけるんじゃないんだ。","ENG":"...Not on your own honor, Deputy?","TWN":"……怎麼不是以副團長的名譽發誓？"},"stage":{"bg":"ROOM_02","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러고보니…… 신경 쓰이는군요, 리브 경.","JPN":"そういえば……リブ卿、怪しいですね。","ENG":"That reminds me, Dame Liv...","TWN":"話說回來……莉芙卿，你有點可疑呢？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님 외에 집무실을 가장 자주 드나들던 사람은 리브 경 아니었나요?","JPN":"団長の他に、執務室にいちばん頻繁に出入りしていたのはリブ卿ではありませんでしたか？","ENG":"You've frequented the Captain's office more than anyone else, haven't you?","TWN":"除了團長，最常進出辦公室的人就是莉你吧？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"자, 잠깐 부단장! 다짜고짜 나부터 의심하는 거야?","JPN":"ちょ、ちょっと副団長！　真っ先に私を疑うの？","ENG":"Wait, what? Deputy, you think I did it?","TWN":"等…等一下，副團長！你問都沒問就先懷疑我嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"합리적인 의심입니다.","JPN":"合理的に疑っているだけです。","ENG":"It's reasonable to think so.","TWN":"我這是合理的懷疑。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경은 평소, 집무실에서 과자나 음식물을 먹고 치우지 않았던 전적이 있지 않습니까.","JPN":"リブ卿には普段から執務室でお菓子などを食べ、後片付けをしなかったという前例があります。","ENG":"Dame Liv, you have a habit of leaving food crumbs in her office.","TWN":"莉芙卿平時在辦公室裡吃餅乾或零食，吃完了都不收拾不是嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그건 그렇지만……!","JPN":"そ、それはそうだけど……！","ENG":"T-true, but...!","TWN":"話…話是沒錯，可是……！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"원래 청소는 막내 몫이잖아? 그렇지, 한솔아?","JPN":"もともと掃除って、末端の責務じゃない！　ねっ、イチロウ？","ENG":"It's the newest member's job to clean her office. Isn't it, Hansol?","TWN":"打掃不是老么的工作嗎？楊瀚，你說是不是？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"네!? 그, 그런 중요한 임무가 있었다니!","JPN":"はい！？　そ、そんな重大な任務が私にあったとは！","ENG":"What? I-I didn't know I had such an important duty!","TWN":"什麼！？竟然…有這麼重要的任務喔！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요, 한솔 경은 막내가 아니라 견습 기사입니다.","JPN":"いえ、ヤガミ卿は末端ではなく、見習い騎士です。","ENG":"No, Sir Hansol isn't a newest member. He's a page.","TWN":"不，楊瀚卿是實習騎士，不是老么。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그리고 <color=#ffd34c>어지럽힌 사람이 치운다.</color> 그런 것쯤은 에리어스 경도 아는 상식일 텐데요.","JPN":"それに<color=#ffd34c>掃除は散らかした人がやる</color>ということぐらい、アリウス卿にもわかるくらい常識的なことでしょう。","ENG":"Most of all, it's common sense that <color=#ffd34c>you clean after yourself.</color> Even our youngest, Dame Arius, knows that.","TWN":"另外，<color=#ffd34c>弄亂的人收拾</color>，這點常識埃里奧斯卿應該也很清楚。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네, 저도 알아요!!","JPN":"はい！　私わかります！","ENG":"Yes, I do!","TWN":"是，我很清楚喔！！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……으아! 억울해!","JPN":"……うわあん！　冤罪よ！","ENG":"...Gah! I'm innocent!","TWN":"……可惡！我是冤枉的！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래, 평소에는 그랬다 쳐. 그래도 이번에는 진짜로 아니라구!","JPN":"普段は確かにそうだったけど、今回は本当に違うんだって！","ENG":"Alright, let's say I do it most times. But I swear, I didn't do it this time!","TWN":"好，平時我是那樣的沒錯，但是這次真的不是我啦！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"증명할 방법이 있습니까.","JPN":"何か証拠はありますか？","ENG":"Can you prove it?","TWN":"你能證明嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"증명?","JPN":"証拠？","ENG":"You want me to prove it?","TWN":"證明？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"맞아! 나한테는 그게 있어. 그 뭐더라…? 알, 알…….","JPN":"そうだ！　私あれがあるの。えーっとなんだっけ。あ、アリ……","ENG":"Oh, yes! I completely forgot I got that. You know, al... al...","TWN":"可以！我有那個，那個叫什麼…？不…不…"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아! <color=#ffd34c>알리바이</color>! 나한테는 <color=#ffd34c>알리바이</color>가 있다구!","JPN":"そう！　<color=#ffd34c>アリバイ</color>！　私には<color=#ffd34c>アリバイ</color>があるの！","ENG":"Ah, <color=#ffd34c>alibi</color>! I've got an <color=#ffd34c>alibi</color>!","TWN":"對啦！<color=#ffd34c>不在場證明</color>！我有<color=#ffd34c>不在場證明</color>！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"근처 카페에서 신 메뉴가 나왔다고 해서 하루 종일 거기 있었단 말이야!","JPN":"近所のカフェに新メニューが出たって聞いたから、一日中そこにいたんだから！","ENG":"I was in a neighborhood coffee shop all day, trying out its new menu.","TWN":"我聽說附近的咖啡廳出了新商品，所以在那待了一整天！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"따라서 집무실에 갈 일이 없었다, 이 말씀!","JPN":"つまり、私は執務室に行かなかったってわけ！","ENG":"Therefore, I didn't have time to be in her office!","TWN":"我根本沒去過辦公室，就是這樣！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘 하루 종일 카페에 있었다고요?","JPN":"今日1日中カフェにいたと？","ENG":"You were in a coffee shop all day today.","TWN":"一整天都待在咖啡廳？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"오늘은 정기훈련이 있는 날 아닙니까, 그런데 훈련을 빠지고 카페에 갔다는 말입니까?","JPN":"今日は定期訓練の日です。それなのに訓練をサボってカフェに行っていたというのですか？","ENG":"Today was our regular training day. You skipped training and went to a coffee shop?","TWN":"今天不是進行定期訓練的日子嗎？但你翹掉訓練，跑去咖啡廳的意思嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으앗…! 그게… 그렇게 되네.","JPN":"ええっ……！　そ、それは……そうなるね。","ENG":"Ah! That's... Yes.","TWN":"呃…！那個……好像是。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……하하, 하하하. 한 번만 봐주라, 부단장~","JPN":"……あはっ、あはははっ。今回だけ見逃してちょうだいよ、副団長～","ENG":"...Hah hah, hah hah hah. Please cut me some slack, Deputy.","TWN":"……哈哈，哈哈哈，這次就饒了我吧，副團長~"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……はぁ。","ENG":"*Sigh...*","TWN":"……呼呼。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"확인차 묻겠습니다만, 오늘 한솔 경과 에리어스 경은 어디 있었습니까?","JPN":"一応確認しますが、ヤガミ卿とアリウス卿は今日どこに？","ENG":"I'm asking you this just as a formality, but Sir Hansol and Dame Arius. Where were you today?","TWN":"那我再確認一下，請問楊瀚卿和埃里奧斯卿，你們今天都在哪裡？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"머리치기 훈련을 하고 있었습니다. 사실, 방금 전까지 하고 있었고요.","JPN":"素振りをしていました。実は、ついさっきまで。","ENG":"I practiced forehead strikes. In fact, I was doing it when you called us.","TWN":"我今天一直都在進練習劍道，一直到剛剛都還在練。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스는 옆에서 숫자를 세주었죠.","JPN":"アリウスさんは隣で回数を数えてくれていました。","ENG":"Arius was next to me, counting the strikes.","TWN":"然後埃里奧斯在旁邊幫我計算次數。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경, 한솔 경의 말이 맞습니까.","JPN":"アリウス卿、ヤガミ卿の話は本当ですか？","ENG":"Dame Arius, is that what you did?","TWN":"埃里奧斯卿，楊瀚卿說的是真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네, 맞아요.","JPN":"はい、間違いないです。","ENG":"Yes.","TWN":"沒錯，是真的。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그럼, 역시 이 중에 알리바이를 증명할 수 없는 사람은 한 명 밖에 없군요.","JPN":"では、やはりこの中にアリバイを証明できない人は1人しかいませんね。","ENG":"Then, there's only one person who can't prove her alibi.","TWN":"意思就是，你們當中只有一個人沒有不在場證明。"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으아~ 진짜 너무해, 부단장!","JPN":"うわあ～ひどいよ、副団長！","ENG":"Wah! This is so unfair, Deputy!","TWN":"嗚嗚～太過分了，副團長！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"나 정말 오늘은 집무실 근처에도 안 왔단 말이야!","JPN":"私、本当に今日は執務室に行ってないんだから！","ENG":"I swear, I wasn't even near the office today!","TWN":"我今天真的沒靠近過辦公室！"},"stage":{"bg":"ROOM_02","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 소란이지?","JPN":"何の騒ぎだ？","ENG":"What's going on?","TWN":"大家在吵什麼？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아, 오셨습니까. 단장님.","JPN":"あっ、団長。","ENG":"Ah, Captain.","TWN":"團長，你來了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으항~ 단장! 살려줘. 부단장이 자꾸 나보고 범인이래!","JPN":"うわーん！　助けて、団長！　副団長が私を犯人扱いしてる！","ENG":"Boohoo! Captain, help me! The Deputy thinks I'm the culprit!","TWN":"嗚嗚～團長，救我！副團長一直說我是犯人！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"범인? 그게 무슨 소리지, 부단장?","JPN":"犯人？　どういうことだ、副団長？","ENG":"What culprit? What is this about, Deputy?","TWN":"犯人？這是什麼意思，副團長？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그게 사실은……","JPN":"あ、それが……","ENG":"Oh, well...","TWN":"是這樣的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그렇게 된 겁니다.","JPN":"……ということです。","ENG":"So, that's what happened.","TWN":"……事情就是這樣。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"죄송합니다. 부단장으로서 단원들의 기강을 바로 잡지 못한 저의 잘못입니다.","JPN":"申し訳ありません。副団長として団員をまとめることができなかった私に落ち度があります。","ENG":"I'm sorry, this is my fault. As deputy captain, I should have disciplined them better.","TWN":"很抱歉，身為副團長，都怪我沒能整頓團員的紀律！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 너무 상심하지 마십시오. 범인은 로웰 가 고조부의 명예를 걸고 반드시 잡겠습니다.","JPN":"ですが、あまり心を傷めないでください。ローウェル家の高祖父の名にかけて、必ず犯人を捕まえてみせます。","ENG":"But please don't be disappointed. I swear on my great grandfather's honor that I'll find out who did this.","TWN":"不過團長你不用太傷心，我以勞威爾家族曾曾祖父的名譽發誓，一定會抓到犯人的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 후, 다시는 이런 일이 발생하지 않도록 그자를 철저히 훈육하겠습니다!","JPN":"そして今後二度とこんなことが起こらないよう、きちんと教育しますので！","ENG":"And I'll make sure they're disciplined!","TWN":"然後我會好好教訓他，以防止這種事再次發生！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님? 얼굴이 붉게 달아오르셨는데… 혹시 어디 편찮으신지……?","JPN":"団長？　顔が赤いですが……どこか具合でも……？","ENG":"Captain? Your face is red. Are you feeling okay?","TWN":"團長？你的臉怎麼這麼紅……是哪裡不舒服嗎……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……벼, 별 것 아니야.","JPN":"……な、なんでもない。","ENG":"...N-nothing.","TWN":"……沒…沒什麼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"머그컵은 이제 괜찮으니까, 다들 집무실에서 나가줄 수 있겠나?","JPN":"マグカップの件は大丈夫だから、みんな執務室から出てくれないか？","ENG":"Forget about the mug. Could you all leave my office now?","TWN":"馬克杯的事就算了，可以請大家離開辦公室嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"역시 너무나 아끼는 머그컵이라 상심이 크신 거군요.","JPN":"やはり、大事にされていたマグカップだから傷心されているのですね。","ENG":"You loved this mug so much that you're heartbroken, aren't you?","TWN":"最愛的馬克杯摔碎了，害你很傷心對吧！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……아니, 그런 게 아니라.","JPN":"……違う、そうじゃなくて。","ENG":"...No, it's not that.","TWN":"……不，不是那樣的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 아무튼 빨리 다들 나가 주었으면……!!","JPN":"と、とにかく早く出てくれ……！","ENG":"Everyone, please just leave—","TWN":"總…總之，你們都快出去……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……멍?","JPN":"……ワン？","ENG":"...Woof?","TWN":"……汪？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"우와, 벽장 속에서 강아지가 튀어 나왔어요.","JPN":"あっ、クローゼットの中からわんちゃんが出てきました。","ENG":"Whoa, a dog came out of the closet!","TWN":"哇，有狗狗從櫃子裡跑出來。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아이, 귀여워라.","JPN":"わあっ、かわいい。","ENG":"How cute!","TWN":"哇～好可愛喔。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이게 대체……?","JPN":"こ、これはいったい……？","ENG":"Wh-what the...?","TWN":"這…這到底是……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……미안하다.","JPN":"……すまない。","ENG":"...Sorry.","TWN":"……很抱歉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"근처에 살고 계시는 할아버지께서 무턱대고 하루만 맡아 달라고 하셔서…….","JPN":"近所に住んでいるおじいさんに、一日だけ預かってくれと頼まれて……","ENG":"An old neighbor asked me to take care of him for just one day…","TWN":"住在附近的爺爺硬要我幫忙照顧一天……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이름은 알렉산더라고 해.","JPN":"名前はアレクサンダーという。","ENG":"His name is Alexander.","TWN":"牠叫亞歷山大。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"예? 그렇다면, 과자 부스러기랑… 휴지 조각이랑… 고기조각 붙은 뼈는…….","JPN":"え？　じゃあ、お菓子の食べかすと、ティッシュ切れと、肉のついた骨って……","ENG":"What? Then... the cookie crumbs, torn napkins, and meaty bones are...","TWN":"嗯？這麼說來，餅乾渣……碎紙片……還有帶肉的骨頭……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"알렉산더랑 잠깐 놀아주다 보니 그만…….","JPN":"アレクサンダーと遊んでいたら、つい……","ENG":"I got carried away, playing with Alexander…","TWN":"因為我跟亞歷山大玩了一下……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 믿어주게. 금방 돌아와서 치우려고 했어.","JPN":"信じてくれ。すぐ帰って片付けるつもりだったんだ。","ENG":"But please believe me. I was going to clean the room when I came back.","TWN":"不過請相信我，我原本是打算馬上就回來收拾的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면, 설마 머그컵도……?","JPN":"ということは、まさかマグカップも……？","ENG":"Then... Oh, no. The mug...?","TWN":"那麼說，該不會那個馬克杯也……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그것도 아마……","JPN":"そ、それも恐らく……","ENG":"P-probably...","TWN":"那…那個可能也是……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……그, 그런!!","JPN":"……そ、そんな！！","ENG":"Th-that's...!","TWN":"……竟…竟然！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"헤헹, 거 봐! 내가 뭐랬어, 나 아니라고 했지?!","JPN":"ふふーん、ほら！　私は違うって言ったでしょ！","ENG":"Hee hee! See? I told you, I was innocent!","TWN":"哼哼，你看吧！我怎麼說的？就說不是我吧？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어라? 그런데 아까 부단장이 뭐라고 했더라?","JPN":"あれっ？　さっき副団長、なんて言ってたっけ？","ENG":"Hmm, but what did you say earlier, Deputy?","TWN":"嗯？不過剛剛副團長是怎麼說的？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그자를 철저하게 훈육 하겠습니다! </color> 였나? 기억이 잘 안 나네~","JPN":"<color=#ffd34c>きちんと教育します！</color>　……だっけ？　ちょっと思い出せないな～","ENG":"<color=#ffd34c>I'll make sure they're disciplined! </color> Wasn't it? Mm, I can't remember...","TWN":"是說<color=#ffd34c>我會好好教訓他！</color>對吧？我沒記錯吧～"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장님을 어떻게 <color=#ffd34c>훈육</color>할 생각일까나~ 부단장니임?","JPN":"団長をどうやって<color=#ffd34c>教育</color>するんだろ～　ねっ？　副団長。","ENG":"Now, how are you going to <color=#ffd34c>discipline</color> the Captain, Deputy?","TWN":"你想怎麼<color=#ffd34c>教訓</color>團長呢～親愛的副團長～？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요, 단장님께서는 아무 잘못 없습니다.","JPN":"いいえ、団長は何も悪くありません。","ENG":"No, the Captain did nothing wrong.","TWN":"不，錯的不是團長。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"모든 것은 부단장으로서 기사단의 대소사를 확인하지 못한 저의 불찰.","JPN":"すべては副団長として騎士団全体を確認できなかった私に非があります。","ENG":"All this is my fault. As deputy, I failed to oversee the affairs of the Knights as thoroughly as I should have.","TWN":"都怪我這個副團長沒有掌握到騎士團的大小事！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……부단장?","JPN":"……副団長？","ENG":"...Deputy?","TWN":"……副團長？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러나 기사로서 제가 선언한 발언은 반드시 지킬 겁니다.","JPN":"ですが、騎士として自分の発言には責任を取るつもりです。","ENG":"But I'm a knight. I keep my word, no matter what.","TWN":"不過身為騎士，我一定會信守諾言。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"로웰 가의 명예를 걸고……!!","JPN":"ローウェル家の名にかけて……！！","ENG":"I swear on my family's honor…!!","TWN":"我以勞威爾家族的榮譽發誓……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"알렉산더! <color=#ffd34c>앉아!</color> 입니다.","JPN":"アレクサンダー！　<color=#ffd34c>おすわり！</color>　です。","ENG":"Alexander! <color=#ffd34c>Sit!</color>","TWN":"亞歷山大！<color=#ffd34c>坐下</color>！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"알렉산더! 그런 나약한 정신으로는 강한 강아지가 될 수 없습니다!","JPN":"アレクサンダー！　そんな甘い精神では、強い犬にはなれません！","ENG":"Alexander! You will never be a strong doggie, acting like that!","TWN":"亞歷山大！無精打采的是要怎麼成為強大的狗狗呢！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다시 하겠습니다. <color=#ffd34c>앉아!</color>","JPN":"もう一度。<color=#ffd34c>おすわり！</color>","ENG":"Let's try again. <color=#ffd34c>Sit!</color>","TWN":"再來一次。<color=#ffd34c>坐下！</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"앉으라고 했는데, 공중 2단 덤블링을 돌고 있어……!","JPN":"おすわりって言ったのに、2回宙返りをしてる……！","ENG":"She said sit, and he's double-somersaulting in the air!","TWN":"明明叫亞歷山大坐下，祂卻在空中翻兩圈欸……！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부, 부단장! 이제 그만해도 될 것 같은데?","JPN":"ふ、副団長！　もうそろそろいいんじゃない？","ENG":"De-Deputy! I think that's enough.","TWN":"副…副團長！夠了吧！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"맞는 말이야, 부단장. 이제 그만해.","JPN":"そうだぞ、副団長。もうやめたらどうだ。","ENG":"She's right, Deputy. Please stop.","TWN":"沒錯，副團長，夠了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아니요. 아무리 사소한 발언이라도 전 제가 한 말은 반드시 지킵니다.","JPN":"いいえ、どんな些細な発言でも、私は自分の言ったことは必ず守ります。","ENG":"No. Like I said, I keep my word, no matter what.","TWN":"不，不管是多麼小的諾言，我都必須一言九鼎。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"알렉산더에게 기사도 정신을 가르치고 말 겁니다.","JPN":"アレクサンダーに騎士道精神を叩きこんでみせます！","ENG":"I'm going to teach Alexander the knightly spirit.","TWN":"我一定要教會亞歷山大什麼是騎士精神。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"알렉산더, <color=#ffd34c>앉아!</color>","JPN":"アレクサンダー、<color=#ffd34c>おすわり！</color>","ENG":"Alexander, <color=#ffd34c>sit!</color>","TWN":"亞歷山大，<color=#ffd34c>坐下！</color>"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};